// BTSidebarItem — single interactive nav row.
// Figma: node 159-1729 (Item).
// CLAUDE.md §12: press state is instant via setState, never AnimatedContainer.

import 'package:btech_tokens/btech_tokens.dart';
import '../../tooltip/tooltip.types.dart';
import '../../tooltip/tooltip.widget.dart';
import 'package:flutter/material.dart';

/// Depth constants.
const int kBTSidebarDepthMain = 0;
const int kBTSidebarDepthSubmenu = 1;
const int kBTSidebarDepthSubSubmenu = 2;

/// Internal nav row widget used exclusively by BTSidebar.
///
/// Handles three display depths (main / submenu / sub-submenu) and the
/// collapsed sidebar mode (32×32 icon-only pill with tooltip).
class BTSidebarItem extends StatefulWidget {
  const BTSidebarItem({
    required this.label,
    required this.depth,
    required this.sidebarOpen,
    required this.onTap,
    this.icon,
    this.active = false,
    this.disabled = false,
    this.hasChildren = false,
    this.expanded = false,
    super.key,
  });

  final String label;

  /// 0 = Main, 1 = Submenu, 2 = Sub Submenu.
  final int depth;

  /// Raw 16×16 icon widget for Main items.
  /// BTSidebarItem wraps it in ColorFiltered for state-driven coloring.
  final Widget? icon;

  final bool active;
  final bool disabled;
  final bool hasChildren;
  final bool expanded;
  final bool sidebarOpen;
  final VoidCallback onTap;

  @override
  State<BTSidebarItem> createState() => _BTSidebarItemState();
}

class _BTSidebarItemState extends State<BTSidebarItem> {
  bool _isHovered = false;
  bool _isPressed = false;

  Color _bgColor(BTColorTheme c) {
    if (widget.disabled) return Colors.transparent;
    if (widget.active) return c.brand.primarySubtle;
    if (_isPressed || _isHovered) return c.bg.secondary;
    return Colors.transparent;
  }

  Color _iconColor(BTColorTheme c) {
    if (widget.disabled) return c.icon.disabled;
    if (widget.active || _isHovered) return c.brand.primary;
    return c.icon.primary;
  }

  Color _labelColor(BTColorTheme c) {
    if (widget.disabled) return c.text.disabled;
    if (widget.active || _isHovered) return c.brand.primary;
    return c.text.primary;
  }

  Color _dotColor(BTColorTheme c) {
    if (widget.disabled) return c.icon.disabled;
    if (widget.active || _isHovered) return c.brand.primary;
    return c.text.secondary;
  }

  FontWeight get _labelWeight {
    if (!widget.active) return FontWeight.w500;
    return widget.depth == 0 ? FontWeight.w700 : FontWeight.w600;
  }

  double get _fontSize => widget.depth == 0 ? 14.0 : 12.0;

  EdgeInsetsGeometry get _padding => widget.depth == kBTSidebarDepthSubSubmenu
      ? EdgeInsetsDirectional.fromSTEB(24.0, 8.0, 8.0, 8.0)
      : EdgeInsets.all(8.0);

  void _handleTap() {
    if (widget.disabled) return;
    widget.onTap();
  }

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;

    // Submenu / Sub Submenu items are hidden when sidebar is collapsed —
    // the children AnimatedSize collapses their parent container.
    if (!widget.sidebarOpen && widget.depth > 0) {
      return const SizedBox.shrink();
    }

    // Collapsed main item — 32×32 centered icon pill with tooltip.
    if (!widget.sidebarOpen && widget.depth == 0) {
      return _buildCollapsed(context, c);
    }

    // Open state — full row.
    return _buildOpen(c);
  }

  Widget _buildCollapsed(BuildContext context, BTColorTheme c) {
    final child = MouseRegion(
      cursor: widget.disabled
          ? SystemMouseCursors.forbidden
          : SystemMouseCursors.click,
      onEnter: widget.disabled
          ? null
          : (_) => setState(() => _isHovered = true),
      onExit: widget.disabled
          ? null
          : (_) => setState(() => _isHovered = false),
      child: GestureDetector(
        onTap: _handleTap,
        onTapDown: widget.disabled
            ? null
            : (_) => setState(() => _isPressed = true),
        onTapUp: widget.disabled
            ? null
            : (_) => setState(() => _isPressed = false),
        onTapCancel:
            widget.disabled ? null : () => setState(() => _isPressed = false),
        child: Container(
          width: 32.0,
          height: 32.0,
          decoration: BoxDecoration(
            color: _bgColor(c),
            borderRadius: BorderRadius.circular(BTRadius.sm),
          ),
          child: Center(
            child: SizedBox(
              width: 16.0,
              height: 16.0,
              child: widget.icon != null
                  ? ColorFiltered(
                      colorFilter:
                          ColorFilter.mode(_iconColor(c), BlendMode.srcIn),
                      child: widget.icon,
                    )
                  : const SizedBox.shrink(),
            ),
          ),
        ),
      ),
    );

    // Tooltip shows the item label to the right when sidebar is collapsed.
    if (widget.label.isEmpty) {
      return Align(alignment: Alignment.center, child: child);
    }
    return Align(
      alignment: Alignment.center,
      child: BTTooltip(
        text: widget.label,
        position: BTTooltipPosition.right,
        child: child,
      ),
    );
  }

  Widget _buildOpen(BTColorTheme c) {
    return MouseRegion(
      cursor: widget.disabled
          ? SystemMouseCursors.forbidden
          : SystemMouseCursors.click,
      onEnter: widget.disabled
          ? null
          : (_) => setState(() => _isHovered = true),
      onExit: widget.disabled
          ? null
          : (_) => setState(() => _isHovered = false),
      child: GestureDetector(
        onTap: _handleTap,
        onTapDown: widget.disabled
            ? null
            : (_) => setState(() => _isPressed = true),
        onTapUp: widget.disabled
            ? null
            : (_) => setState(() => _isPressed = false),
        onTapCancel:
            widget.disabled ? null : () => setState(() => _isPressed = false),
        child: Container(
          decoration: BoxDecoration(
            color: _bgColor(c),
            borderRadius: BorderRadius.circular(BTRadius.sm),
          ),
          padding: _padding,
          child: Row(
            children: [
              // Icon (Main) or dot indicator (Submenu / Sub Submenu)
              if (widget.depth == 0)
                SizedBox(
                  width: 16.0,
                  height: 16.0,
                  child: widget.icon != null
                      ? ColorFiltered(
                          colorFilter:
                              ColorFilter.mode(_iconColor(c), BlendMode.srcIn),
                          child: widget.icon,
                        )
                      : const SizedBox.shrink(),
                )
              else
                _buildDot(c),

              SizedBox(width: 4.0),

              // Label
              Expanded(
                child: Text(
                  widget.label,
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: _fontSize,
                    fontWeight: _labelWeight,
                    height: 16 / _fontSize,
                    color: _labelColor(c),
                  ),
                ),
              ),

              // Chevron — only for items with children
              if (widget.hasChildren) ...[
                SizedBox(width: 4.0),
                AnimatedRotation(
                  turns: widget.expanded ? 0.25 : 0.0,
                  duration: const Duration(milliseconds: 200),
                  child: Icon(
                    Icons.chevron_right,
                    size: 16,
                    color: c.text.secondary,
                  ),
                ),
              ],
            ],
          ),
        ),
      ),
    );
  }

  Widget _buildDot(BTColorTheme c) {
    return SizedBox(
      width: 16.0,
      height: 16.0,
      child: Center(
        child: Container(
          width: 8.0,
          height: 8.0,
          decoration: BoxDecoration(
            color: _dotColor(c),
            shape: BoxShape.circle,
          ),
        ),
      ),
    );
  }
}

// BTSidebar — collapsible navigation sidebar.
// Figma: node 2389-6285 (M-Sidebar).
//
// Public API:
//   - BTSidebar widget
//   - BTSidebarNavItem sealed class + subtypes
//   - BTSidebarHeader, BTSidebarFooterUser
export 'package:btech_ui/src/components/organisms/sidebar/sidebar.types.dart';
export 'package:btech_ui/src/components/organisms/sidebar/sidebar.widget.dart';

// BTSidebar types — Figma: node 2389-6285 (M-Sidebar).

import 'package:flutter/widgets.dart';

export 'package:btech_ui/src/components/molecules/avatar/avatar.types.dart'
    show BTAvatarItem;

/// Sealed nav item hierarchy — exhaustively matched in BTSidebar.
sealed class BTSidebarNavItem {
  const BTSidebarNavItem({required this.id});
  final String id;
}

/// Top-level main item — icon + label row, optionally expandable.
final class BTSidebarMain extends BTSidebarNavItem {
  const BTSidebarMain({
    required super.id,
    required this.label,
    this.icon,
    this.active = false,
    this.disabled = false,
    this.children = const [],
  });

  final String label;

  /// 16×16 icon widget (SvgPicture.asset recommended).
  /// Pass the raw widget — BTSidebar applies ColorFiltered for state coloring.
  final Widget? icon;

  final bool active;
  final bool disabled;
  final List<BTSidebarNavItem> children;
}

/// Level-2 submenu item — dot indicator, optionally expandable.
final class BTSidebarSubmenu extends BTSidebarNavItem {
  const BTSidebarSubmenu({
    required super.id,
    required this.label,
    this.active = false,
    this.disabled = false,
    this.children = const [],
  });

  final String label;
  final bool active;
  final bool disabled;
  final List<BTSidebarNavItem> children;
}

/// Level-3 sub-submenu item — deeper indent, dot indicator.
final class BTSidebarSubSubmenu extends BTSidebarNavItem {
  const BTSidebarSubSubmenu({
    required super.id,
    required this.label,
    this.active = false,
    this.disabled = false,
  });

  final String label;
  final bool active;
  final bool disabled;
}

/// Uppercase section label — hidden when sidebar is collapsed.
final class BTSidebarSubTitle extends BTSidebarNavItem {
  const BTSidebarSubTitle({required super.id, required this.label});
  final String label;
}

/// Horizontal separator line.
final class BTSidebarDivider extends BTSidebarNavItem {
  const BTSidebarDivider({required super.id});
}

/// Optional sidebar header — logo widget + title + description.
///
/// ```dart
/// BTSidebarHeader(
///   logo: ClipRRect(
///     borderRadius: BorderRadius.circular(6),
///     child: SvgPicture.asset('assets/logo.svg', width: 32, height: 32),
///   ),
///   title: 'App',
///   description: 'Workspace',
/// )
/// ```
class BTSidebarHeader {
  const BTSidebarHeader({
    this.logo,
    this.title,
    this.description,
  });

  /// Logo widget rendered at 32×32 in the sidebar header.
  /// Accepts any widget — SvgPicture.asset, Image.network, custom widget, etc.
  /// Clipping/radius is the consumer's responsibility (wrap in ClipRRect if needed).
  final Widget? logo;

  /// Bold 14 px workspace / app title.
  final String? title;

  /// Subdued 12 px description / subtitle.
  final String? description;
}

/// BTSidebar — collapsible navigation sidebar.
/// Figma: node 2389-6285 (M-Sidebar).
///
/// Composes:
///   - BTAvatar       (footer user avatar, size sm)
///   - BTButton       (toggle icon-only, secondary-light)
///   - BTInputSearch  (search row, shown when [searchValue] is non-null)
///   - BTSidebarItem  (each interactive nav row, internal)
///
/// Width: 258 px open → 64 px collapsed.
/// Layout: header always contains [logo + text | toggle], search row is
///   separate (only when open). Footer at the bottom.
/// Animations: AnimatedContainer (sidebar width + padding, 300 ms),
///   AnimatedSize (children expand/collapse + subtitle hide, 250 ms),
///   AnimatedOpacity (header/footer text fade, 200 ms).
///
/// ## Usage:
/// ```dart
/// BTSidebar(
///   open: _sidebarOpen,
///   header: BTSidebarHeader(
///     logo: ClipRRect(
///       borderRadius: BorderRadius.circular(6),
///       child: SvgPicture.asset('assets/logo.svg', width: 32, height: 32),
///     ),
///     title: 'Workspace',
///     description: 'My Team',
///   ),
///   items: _navItems,
///   footer: BTSidebarFooterUser(
///     item: BTAvatarItem(name: 'John Doe', imageUrl: 'https://...'),
///     email: 'john@example.com',
///   ),
///   onToggle: () => setState(() => _sidebarOpen = !_sidebarOpen),
///   onItemClick: (item) => _navigate(item.id),
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import '../scrollbar/scrollbar.widget.dart';
import '../avatar/avatar.types.dart';
import '../avatar/avatar.widget.dart';
import '../input-search/input_search.widget.dart';
import 'package:btech_ui/src/components/organisms/sidebar/internal/sidebar_item.dart';
import 'package:btech_ui/src/components/organisms/sidebar/sidebar.types.dart';
import 'package:flutter/material.dart';

export 'sidebar.types.dart';

const _kOpenWidth = 258.0;
const _kCollapsedWidth = 64.0;
const _kAnimDuration = Duration(milliseconds: 300);
const _kChildrenDuration = Duration(milliseconds: 250);
const _kFadeDuration = Duration(milliseconds: 200);

/// Optional footer user info for the sidebar footer area.
class BTSidebarFooterUser {
  const BTSidebarFooterUser({this.item, this.email});

  final BTAvatarItem? item;
  final String? email;
}

/// Collapsible navigation sidebar. See file header for usage examples.
class BTSidebar extends StatefulWidget {
  const BTSidebar({
    required this.open,
    required this.onToggle,
    this.header,
    this.items = const [],
    this.searchValue,
    this.footer,
    this.footerWidget,
    this.initialExpandedIds = const [],
    this.onSearch,
    this.onItemClick,
    super.key,
  });

  /// Expanded (258 px) when true, collapsed (64 px) when false.
  final bool open;

  /// Called when the toggle button is tapped.
  final VoidCallback onToggle;

  /// Optional header: logo Widget + title + description.
  /// When null, only the toggle button appears at the top of the sidebar.
  final BTSidebarHeader? header;

  /// Navigation item tree (Main → Submenu → Sub Submenu).
  final List<BTSidebarNavItem> items;

  /// Current text value for the search input.
  /// BTInputSearch is always shown when the sidebar is open — pass this to
  /// control the text from outside. Null lets BTInputSearch manage its own
  /// internal state.
  final String? searchValue;

  /// Footer user info (avatar + email). Use [footerWidget] for custom content.
  final BTSidebarFooterUser? footer;

  /// Custom footer widget — overrides [footer].
  final Widget? footerWidget;

  /// IDs of items that should start expanded.
  final List<String> initialExpandedIds;

  /// Called when the search input changes or submits.
  final ValueChanged<String>? onSearch;

  /// Called when a nav item is tapped.
  final ValueChanged<BTSidebarNavItem>? onItemClick;

  @override
  State<BTSidebar> createState() => _BTSidebarState();
}

class _BTSidebarState extends State<BTSidebar> {
  late Set<String> _expandedIds;
  late final ScrollController _navScrollController;

  /// Tracks whether the sidebar is fully open (animation complete).
  ///
  /// Unlike [BTSidebar.open], this lags behind when opening — it stays
  /// `false` while the AnimatedContainer is expanding so that nav items
  /// remain in collapsed mode. This prevents RenderFlex overflow errors
  /// from rows that are too wide for the 64 px container during animation.
  /// When closing it snaps to `false` immediately (collapsed content
  /// comfortably fits in 64 px).
  late bool _effectivelyOpen;

  @override
  void initState() {
    super.initState();
    _expandedIds = Set<String>.from(widget.initialExpandedIds);
    _navScrollController = ScrollController();
    _effectivelyOpen = widget.open;
  }

  @override
  void dispose() {
    _navScrollController.dispose();
    super.dispose();
  }

  @override
  void didUpdateWidget(BTSidebar old) {
    super.didUpdateWidget(old);
    if (old.open && !widget.open) {
      // Closing: snap content to collapsed immediately so collapsed icons
      // are already showing before the container finishes shrinking.
      setState(() {
        _expandedIds = {};
        _effectivelyOpen = false;
      });
    } else if (!old.open && widget.open) {
      // Opening: delay switching nav to open mode until the AnimatedContainer
      // finishes expanding.  This prevents rows from overflowing the narrow
      // (64 px) container during the animation.
      Future.delayed(_kAnimDuration, () {
        if (mounted && widget.open) setState(() => _effectivelyOpen = true);
      });
    }
  }

  bool _isExpanded(String id) => _expandedIds.contains(id);

  void _toggleExpand(String id) {
    setState(() {
      if (_expandedIds.contains(id)) {
        _expandedIds.remove(id);
      } else {
        _expandedIds.add(id);
      }
    });
  }

  void _handleItemTap(BTSidebarNavItem item) {
    final hasChildren = switch (item) {
      BTSidebarMain(:final children) => children.isNotEmpty,
      BTSidebarSubmenu(:final children) => children.isNotEmpty,
      _ => false,
    };
    if (hasChildren) _toggleExpand(item.id);
    widget.onItemClick?.call(item);
  }

  // ── Build ──────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final open = widget.open;
    // Use _effectivelyOpen (not open) for nav content to prevent overflow
    // errors while the AnimatedContainer is mid-animation.
    final effectivelyOpen = _effectivelyOpen;

    return AnimatedContainer(
      duration: _kAnimDuration,
      curve: Curves.easeInOut,
      width: open ? _kOpenWidth : _kCollapsedWidth,
      constraints: BoxConstraints(
        minWidth: open ? _kOpenWidth : _kCollapsedWidth,
        maxWidth: open ? _kOpenWidth : _kCollapsedWidth,
      ),
      decoration: BoxDecoration(
        color: c.bg.primary,
        border: BorderDirectional(
          end: BorderSide(color: c.border.primary),
        ),
      ),
      // Horizontal padding is applied per-section (header, search, footer,
      // and nav content) so the BTScrollbar can bleed to the sidebar border.
      padding: EdgeInsets.symmetric(vertical: 16.0),
      clipBehavior: Clip.hardEdge,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Header — always shown; contains logo + text + toggle button ──
          _buildHeader(context, c, open),

          // ── Search row — only when effectively open ──────────────────────
          // Uses effectivelyOpen (not open) so BTInputSearch is not inflated
          // into the still-narrow container during the opening animation.
          _buildSearchRow(context, c, effectivelyOpen),

          // ── Nav ─────────────────────────────────────────────────────────
          // BTScrollbar spans the full sidebar width (no horizontal padding on
          // the Expanded) so the track/thumb sits flush against the sidebar
          // border — matching the web CSS margin: 0 -16px; padding: 0 16px
          // trick. Horizontal padding is applied to the content Padding inside.
          Expanded(
            child: BTScrollbar(
              controller: _navScrollController,
              child: SingleChildScrollView(
                controller: _navScrollController,
                child: Padding(
                  // Uses effectivelyOpen so padding snaps only after the
                  // container finishes expanding — preventing layout mismatch.
                  padding: EdgeInsets.symmetric(
                    horizontal: effectivelyOpen ? 16 : 0,
                  ),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.stretch,
                    children: () {
                      // Collapsed / animating: only Main (group) items and
                      // Dividers shown. SubTitle, Submenu children, etc. are
                      // excluded entirely so there is no blank space.
                      final visible = effectivelyOpen
                          ? widget.items
                          : widget.items
                              .where((item) =>
                                  item is BTSidebarMain ||
                                  item is BTSidebarDivider,
                              )
                              .toList();
                      return [
                        for (int i = 0; i < visible.length; i++) ...[
                          if (i > 0) SizedBox(height: 16.0),
                          _buildNavItem(context, visible[i], 0),
                        ],
                      ];
                    }(),
                  ),
                ),
              ),
            ),
          ),

          // ── Footer ──────────────────────────────────────────────────────
          // Uses effectivelyOpen (not open) so the Row with avatar + text is
          // not inflated into the still-narrow container during opening.
          if (widget.footerWidget != null || widget.footer != null)
            _buildFooter(context, c, effectivelyOpen),
        ],
      ),
    );
  }

  // ── Header ────────────────────────────────────────────────────────────────
  // Always rendered. The toggle button lives here (inline-end side) so it
  // remains visible whether the sidebar is open or collapsed.

  Widget _buildHeader(BuildContext context, BTColorTheme c, bool open) {
    final h = widget.header;

    // Toggle button — always at the trailing edge of the header row.
    final toggleBtn = BTButton.iconOnly(
      variant: BTButtonVariant.secondaryLight,
      size: BTButtonSize.sm,
      onPressed: widget.onToggle,
      icon: Icon(
        open ? Icons.close : Icons.menu,
        size: 16,
        color: c.text.primary,
      ),
    );

    // No header content: toggle only, centered when collapsed.
    if (h == null) {
      return Padding(
        padding: EdgeInsetsDirectional.fromSTEB(
          open ? 16.0 : 0, 0, open ? 16.0 : 0, 16.0,
        ),
        child: Row(
          mainAxisAlignment:
              open ? MainAxisAlignment.end : MainAxisAlignment.center,
          children: [toggleBtn],
        ),
      );
    }

    return Padding(
      padding: EdgeInsetsDirectional.fromSTEB(
        open ? 16.0 : 0, 0, open ? 16.0 : 0, 16,
      ),
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.center,
        // When open: start + Spacer pushes toggle to trailing edge.
        // When collapsed: center so the lone toggle sits in the middle of the
        // 64 px sidebar (consistent with the centered nav icons below).
        mainAxisAlignment:
            open ? MainAxisAlignment.start : MainAxisAlignment.center,
        children: [
          // Logo — collapses to zero when sidebar closes (same as text).
          AnimatedSize(
            duration: _kAnimDuration,
            curve: Curves.easeInOut,
            alignment: AlignmentDirectional.centerStart,
            child: open && h.logo != null
                ? Padding(
                    padding: const EdgeInsetsDirectional.only(end: 8),
                    child: h.logo,
                  )
                : const SizedBox.shrink(),
          ),

          // Title + description — collapses to zero when sidebar closes.
          AnimatedSize(
            duration: _kAnimDuration,
            curve: Curves.easeInOut,
            alignment: AlignmentDirectional.centerStart,
            child: open
                ? ConstrainedBox(
                    constraints: BoxConstraints(maxWidth: 180.0),
                    child: AnimatedOpacity(
                      opacity: 1,
                      duration: _kFadeDuration,
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          if (h.title != null)
                            Text(
                              h.title!,
                              maxLines: 1,
                              overflow: TextOverflow.ellipsis,
                              style: TextStyle(
                                fontFamily: BTTypography.fontFamily,
                                fontSize: 14.0,
                                fontWeight: FontWeight.w700,
                                height: 20 / 14,
                                color: c.text.primary,
                              ),
                            ),
                          if (h.description != null)
                            Text(
                              h.description!,
                              maxLines: 1,
                              overflow: TextOverflow.ellipsis,
                              style: TextStyle(
                                fontFamily: BTTypography.fontFamily,
                                fontSize: 12.0,
                                fontWeight: FontWeight.w500,
                                height: 16 / 12,
                                color: c.text.secondary,
                              ),
                            ),
                        ],
                      ),
                    ),
                  )
                : const SizedBox.shrink(),
          ),

          // Spacer only when open — fills gap between text and toggle.
          // Removed when collapsed so mainAxisAlignment.center can work.
          if (open) const Spacer(),

          // Toggle button — trailing edge when open, centered when collapsed.
          toggleBtn,
        ],
      ),
    );
  }

  // ── Search row ──────────────────────────────────────────────────────────
  // Toggle moved into header — this row only shows BTInputSearch.

  Widget _buildSearchRow(BuildContext context, BTColorTheme c, bool open) {
    if (!open) return const SizedBox.shrink();
    return Padding(
      padding: EdgeInsets.fromLTRB(16.0, 0, 16.0, 16.0),
      child: BTInputSearch(
        value: widget.searchValue,
        onChanged: widget.onSearch,
        onSearch: widget.onSearch,
      ),
    );
  }

  // ── Nav item dispatch ─────────────────────────────────────────────────────

  Widget _buildNavItem(
    BuildContext context,
    BTSidebarNavItem item,
    int depth,
  ) {
    return switch (item) {
      BTSidebarDivider() => _buildDivider(context),
      BTSidebarSubTitle(:final label) => _buildSubTitle(context, label),
      BTSidebarMain() => _buildMainGroup(context, item),
      BTSidebarSubmenu() => _buildSubmenuGroup(context, item),
      BTSidebarSubSubmenu() => _buildSubSubmenuRow(context, item),
    };
  }

  Widget _buildDivider(BuildContext context) {
    final c = context.btColor;
    final open = widget.open;
    return Padding(
      padding: EdgeInsets.symmetric(vertical: 8.0),
      child: open
          ? Container(height: 1, color: c.border.primary)
          : Align(
              alignment: Alignment.center,
              child: SizedBox(
                width: 32.0,
                height: 1,
                child: ColoredBox(color: c.border.primary),
              ),
            ),
    );
  }

  Widget _buildSubTitle(BuildContext context, String label) {
    final c = context.btColor;
    return AnimatedSize(
      duration: _kAnimDuration,
      curve: Curves.easeInOut,
      alignment: AlignmentDirectional.topStart,
      child: widget.open
          ? AnimatedOpacity(
              opacity: widget.open ? 1.0 : 0.0,
              duration: _kFadeDuration,
              child: Padding(
                padding: EdgeInsetsDirectional.fromSTEB(4.0, 8.0, 0, 8.0),
                child: Text(
                  label.toUpperCase(),
                  style: TextStyle(
                    fontFamily: BTTypography.fontFamily,
                    fontSize: 12.0,
                    fontWeight: FontWeight.w500,
                    height: 16 / 12,
                    color: c.text.secondary,
                    letterSpacing: 0.06 * 12,
                  ),
                ),
              ),
            )
          : const SizedBox.shrink(),
    );
  }

  Widget _buildMainGroup(BuildContext context, BTSidebarMain item) {
    final expanded = _isExpanded(item.id);
    final effectivelyOpen = _effectivelyOpen;
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        BTSidebarItem(
          key: ValueKey(item.id),
          label: item.label,
          depth: kBTSidebarDepthMain,
          icon: item.icon,
          active: item.active,
          disabled: item.disabled,
          hasChildren: item.children.isNotEmpty,
          expanded: expanded,
          sidebarOpen: effectivelyOpen,
          onTap: () => _handleItemTap(item),
        ),

        // Level-2 children
        if (item.children.isNotEmpty)
          AnimatedSize(
            duration: _kChildrenDuration,
            curve: Curves.easeInOut,
            alignment: Alignment.topCenter,
            child: expanded && effectivelyOpen
                ? Padding(
                    padding: EdgeInsets.only(top: 16.0),
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.stretch,
                      children: [
                        for (int i = 0; i < item.children.length; i++) ...[
                          if (i > 0) SizedBox(height: 16.0),
                          _buildNavItem(context, item.children[i], 1),
                        ],
                      ],
                    ),
                  )
                : const SizedBox.shrink(),
          ),
      ],
    );
  }

  Widget _buildSubmenuGroup(BuildContext context, BTSidebarSubmenu item) {
    final expanded = _isExpanded(item.id);
    final effectivelyOpen = _effectivelyOpen;
    return Column(
      crossAxisAlignment: CrossAxisAlignment.stretch,
