  }

  // ── Footer ────────────────────────────────────────────────────────────────

  Widget _buildFooter(BuildContext context, BTColorTheme c, bool open) {
    final customFooter = widget.footerWidget;
    if (customFooter != null) {
      return Padding(
        padding: EdgeInsetsDirectional.fromSTEB(
          open ? 16.0 : 0, 16.0, open ? 16.0 : 0, 0,
        ),
        child: customFooter,
      );
    }

    final f = widget.footer;
    if (f == null) return const SizedBox.shrink();
    return Padding(
      padding: EdgeInsetsDirectional.fromSTEB(
        open ? 16.0 : 0, 16, open ? 16.0 : 0, 0,
      ),
      child: open
          ? Row(
              children: [
                BTAvatar(item: f.item, size: BTAvatarSize.sm),
                SizedBox(width: 8.0),
                Flexible(
                  child: AnimatedOpacity(
                    opacity: open ? 1.0 : 0.0,
                    duration: _kFadeDuration,
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      mainAxisSize: MainAxisSize.min,
                      children: [
                        if (f.item != null)
                          Text(
                            f.item!.name,
                            maxLines: 1,
                            overflow: TextOverflow.ellipsis,
                            style: TextStyle(
                              fontFamily: BTTypography.fontFamily,
                              fontSize: 14.0,
                              fontWeight: FontWeight.w700,
                              height: 20 / 14,
                              color: c.text.primary,
                            ),
                          ),
                        if (f.email != null)
                          Text(
                            f.email!,
                            maxLines: 1,
                            overflow: TextOverflow.ellipsis,
                            style: TextStyle(
                              fontFamily: BTTypography.fontFamily,
                              fontSize: 12.0,
                              fontWeight: FontWeight.w500,
                              height: 16 / 12,
                              color: c.text.secondary,
                            ),
                          ),
                      ],
                    ),
                  ),
                ),
              ],
            )
          : Align(
              alignment: Alignment.center,
              child: BTAvatar(item: f.item, size: BTAvatarSize.sm),
            ),
    );
  }
